#!/usr/bin/env node
// Generated by Meshly Build Station — shared helpers for the Meshly process-
// enforcement hooks. Do not edit by hand — overwritten on the next resync.
import { readFileSync } from "node:fs";
import { execSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const HERE = dirname(fileURLToPath(import.meta.url));
// A dispatched (background) agent runs with `--strict-mcp-config` against a
// per-spawn config pinned to ITS assignee, and Station sets MESHLY_MCP_CONFIG to
// that same file. Prefer it so the hook authenticates as the dispatched agent —
// not whoever the working-dir `.mcp.json` was generated for. Interactive
// sessions (no env var) fall back to the working-dir file.
const MCP_JSON = process.env.MESHLY_MCP_CONFIG || join(HERE, "..", "..", ".mcp.json");

// Pull the Bearer key out of a {"Authorization":"Bearer …"} header map.
function keyFromHeaders(headers) {
  const auth = (headers && (headers.Authorization || headers.authorization)) || "";
  return auth.replace(/^Bearer\s+/i, "").trim();
}

// { apiKey, baseUrl, projectId } from .mcp.json, or null (fail-open).
export function loadMeshly() {
  try {
    const cfg = JSON.parse(readFileSync(MCP_JSON, "utf8"));
    const server = cfg && cfg.mcpServers && cfg.mcpServers["meshly-build"];
    if (!server || !server.url) return null;

    // Prefer an inline header (legacy configs); otherwise run the same
    // headersHelper command Claude uses, which reads the key from the keychain.
    let apiKey = keyFromHeaders(server.headers);
    if (!apiKey && server.headersHelper) {
      try {
        const out = execSync(server.headersHelper, { timeout: 5000, encoding: "utf8" });
        apiKey = keyFromHeaders(JSON.parse(out));
      } catch {
        return null;
      }
    }
    if (!apiKey) return null;

    const projectId = new URL(server.url).searchParams.get("project");
    const baseUrl = server.url.split("/mcp/sse")[0];
    if (!projectId || !baseUrl) return null;
    return { apiKey, baseUrl, projectId };
  } catch {
    return null;
  }
}

// { has_active, task_id, title } from GET /tasks/active, or null on ANY
// failure/timeout (fail-open — never block on a flaky backend).
export async function getActiveTask(timeoutMs = 2500) {
  const m = loadMeshly();
  if (!m) return null;
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), timeoutMs);
  try {
    const res = await fetch(
      m.baseUrl + "/tasks/active?project_id=" + encodeURIComponent(m.projectId),
      { headers: { Authorization: "Bearer " + m.apiKey }, signal: ctrl.signal }
    );
    if (!res.ok) return null;
    return await res.json();
  } catch {
    return null;
  } finally {
    clearTimeout(timer);
  }
}
